import { ChangeDetectionStrategy, Component, inject, signal } from '@angular/core';
import {
  AXCookieStorageService,
  AXLocalStorageService,
  AXSessionStorageService,
} from '@acorex/core/storage';

interface UserPrefs {
  theme: 'light' | 'dark';
  locale: 'en-US' | 'fa-IR';
}

@Component({
  selector: 'app-storage-basic-usage',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (prefs(); as currentPrefs) {
      <p>Theme: {{ currentPrefs.theme }}</p>
      <p>Locale: {{ currentPrefs.locale }}</p>
    } @else {
      <p>No preferences saved yet.</p>
    }

    <p>Wizard step: {{ draft().step }}</p>
    <p>Cookie consent: {{ cookieConsent() ? 'accepted' : 'pending' }}</p>

    <button type="button" (click)="savePreferences()">Save preferences</button>
    <button type="button" (click)="saveDraft()">Save draft</button>
    <button type="button" (click)="acceptCookies()">Accept cookies</button>
    <button type="button" (click)="clear()">Clear</button>
  `,
})
export class StorageBasicUsageComponent {
  private readonly localStorage = inject(AXLocalStorageService);
  private readonly sessionStorage = inject(AXSessionStorageService);
  private readonly cookieStorage = inject(AXCookieStorageService);

  protected readonly prefs = signal<UserPrefs | null>(this.localStorage.get<UserPrefs>('APP_PREFS'));
  protected readonly draft = signal(this.sessionStorage.get<{ step: number }>('CHECKOUT_DRAFT') || { step: 1 });
  protected readonly cookieConsent = signal(this.cookieStorage.check('cookie_consent'));

  savePreferences() {
    const nextPrefs: UserPrefs = { theme: 'dark', locale: 'en-US' };
    this.localStorage.set('APP_PREFS', nextPrefs);
    this.prefs.set(nextPrefs);
  }

  saveDraft() {
    const nextDraft = { step: this.draft().step + 1 };
    this.sessionStorage.set('CHECKOUT_DRAFT', nextDraft);
    this.draft.set(nextDraft);
  }

  acceptCookies() {
    this.cookieStorage.set('cookie_consent', 'accepted', {
      path: '/',
      expires: 365,
      sameSite: 'Lax',
      secure: true,
    });
    this.cookieConsent.set(true);
  }

  clear() {
    this.localStorage.removeItem('APP_PREFS');
    this.sessionStorage.removeItem('CHECKOUT_DRAFT');
    this.cookieStorage.delete('cookie_consent', '/');
    this.prefs.set(null);
    this.draft.set({ step: 1 });
    this.cookieConsent.set(false);
  }
}

import { Component, inject, signal } from '@angular/core';
import { AXLocalStorageService } from '@acorex/core/storage';

interface UserPrefs {
  sidebarCollapsed: boolean;
  lastVisited: string;
}

@Component({
  selector: 'app-preferences',
  providers: [AXLocalStorageService],
  template: `
    <button type="button" (click)="save()">Save</button>
    <button type="button" (click)="load()">Load</button>
  `,
})
export class PreferencesComponent {
  private storage = inject(AXLocalStorageService);
  private readonly KEY = 'USER_PREFS';

  prefs = signal<UserPrefs | null>(null);

  save() {
    this.storage.set<UserPrefs>(this.KEY, {
      sidebarCollapsed: true,
      lastVisited: '/dashboard',
    });
  }

  load() {
    const saved = this.storage.get<UserPrefs>(this.KEY);
    this.prefs.set(saved);
  }

  clear() {
    this.storage.removeItem(this.KEY);
  }
}

import { inject } from '@angular/core';
import { AXLocalStorageService } from '@acorex/core/storage';

interface AuthTokens {
  accessToken: string;
  refreshToken: string;
}

function saveTokens(tokens: AuthTokens) {
  const storage = inject(AXLocalStorageService);
  storage.setWithEncryption('AUTH_TOKENS', tokens);
}

function loadTokens(): AuthTokens | null {
  const storage = inject(AXLocalStorageService);
  return storage.getWithEncription<AuthTokens>('AUTH_TOKENS');
}

