import { Component, inject } from '@angular/core';
import { AXSessionStorageService } from '@acorex/core/storage';

@Component({
  selector: 'app-wizard',
  providers: [AXSessionStorageService],
  template: `<p>Step {{ step }}</p>`,
})
export class WizardComponent {
  private session = inject(AXSessionStorageService);
  step = 1;

  ngOnInit() {
    const saved = this.session.get<{ step: number }>('WIZARD_STATE');
    if (saved) this.step = saved.step;
  }

  nextStep() {
    this.step++;
    this.session.set('WIZARD_STATE', { step: this.step });
  }

  ngOnDestroy() {
    // Optional: clear when wizard completes
    // this.session.removeItem('WIZARD_STATE');
  }
}

import { inject } from '@angular/core';
import { AXCookieStorageService } from '@acorex/core/storage';

function manageCookies() {
  const cookies = inject(AXCookieStorageService);

  // Set with options object
  cookies.set('session_id', 'abc123', {
    path: '/',
    expires: 7,        // 7 days
    secure: true,
    sameSite: 'Lax',
  });

  // Check existence
  if (cookies.check('session_id')) {
    console.log(cookies.get('session_id'));
  }

  // Read all cookies
  console.log(cookies.getAll());

  // Delete one
  cookies.delete('session_id', '/');

  // Delete all (optionally scoped by path/domain)
  // cookies.deleteAll('/');
}

import { inject, Injectable } from '@angular/core';
import { AXPlatform } from '@acorex/core/platform';
import { AXLocalStorageService } from '@acorex/core/storage';

type AXLangLocale = 'en-US' | 'fa-IR';

@Injectable({ providedIn: 'root' })
export class LayoutService {
  private localStorage = inject(AXLocalStorageService);
  private platform = inject(AXPlatform);

  init() {
    const locale = this.localStorage.get<AXLangLocale>('AX_LANG');
    if (locale) {
      this.applyLocale(locale);
    }
    this.platform.autoDetectThemeMode();
  }

  toggleTheme() {
    const theme = this.platform.autoDetectThemeMode();
    this.localStorage.set('AX_THEME_MODE', theme);
  }

  switchLang(locale: AXLangLocale) {
    this.localStorage.set('AX_LANG', locale);
    this.applyLocale(locale);
  }

  private applyLocale(locale: AXLangLocale) {
    // e.g. localeService.setProfile(locale)
  }
}

import { afterNextRender, inject } from '@angular/core';
import { AXLocalStorageService } from '@acorex/core/storage';

function restoreUserState() {
  const storage = inject(AXLocalStorageService);

  // get() returns null during SSR — defer restore to browser
  afterNextRender(() => {
    const user = storage.get<{ name: string }>('CURRENT_USER');
    if (user) {
      console.log('Welcome back', user.name);
    }
  });
}

import { AXStorage, AXLocalStorageService, AXSessionStorageService } from '@acorex/core/storage';

function persistDraft(storage: AXStorage, key: string, data: unknown) {
  storage.set(key, data);
}

// Use local for long-lived drafts
persistDraft(localStorageService, 'DRAFT', { title: 'Hello' });

// Use session for tab-only drafts
persistDraft(sessionStorageService, 'DRAFT', { title: 'Hello' });
